// Connection arcs between related locations
const CONNECTIONS = [];
const connectionSet = new Set();
LOCATIONS.forEach(loc => {
  loc.connections.forEach(targetId => {
    const key = [loc.id, targetId].sort().join('-');
    if (!connectionSet.has(key)) {
      connectionSet.add(key);
      const target = LOCATIONS.find(l => l.id === targetId);
      if (target) {
        CONNECTIONS.push({
          startLat: loc.lat,
          startLng: loc.lng,
          endLat: target.lat,
          endLng: target.lng,
          fromId: loc.id,
          toId: target.id,
          fromName: loc.name,
          toName: target.name
        });
      }
    }
  });
});

